/* TrainingCard.jsx */
import React from 'react';
import './TrainingCard.css';

function StarRating({ rating }) {
  const r = rating || 0;
  return (
    <div className="tcard__stars">
      {[1,2,3,4,5].map(i => (
        <span key={i} className={`tcard__star ${i <= Math.round(r) ? 'tcard__star--filled' : ''}`}>★</span>
      ))}
      <span className="tcard__rating-num">{r.toFixed(1)}</span>
    </div>
  );
}

export default function TrainingCard({ training, onOpenModal }) {
  const {
    title        = 'Untitled Course',
    category     = 'General',
    tagColor     = 'lavender',
    level        = 'Beginner',
    description  = '',
    duration     = '',
    price        = 0,
    enrolled     = 0,
    rating       = 0,
    reviews      = 0,
    tags,
    provider,
    providerLogo,
    logoColor,
    featured,
  } = training || {};

  // Use tags if available, otherwise use category
  const displayTags = Array.isArray(tags) && tags.length > 0
    ? tags.slice(0, 2)
    : [category];

  const color = tagColor || 'lavender';

  return (
    <div className="tcard" onClick={() => onOpenModal && onOpenModal(training)}
      style={{ cursor: 'pointer' }}>

      {/* Thumbnail */}
      <div className="tcard__thumb"
        style={{ '--thumb-color': logoColor || `var(--${color})` }}>
        <div className="tcard__thumb-inner">
          <span className="tcard__thumb-logo">
            {providerLogo || category?.slice(0, 2).toUpperCase() || '🎓'}
          </span>
          {featured && <span className="tcard__thumb-badge">⚡ Popular</span>}
        </div>
        <div className="tcard__thumb-overlay">
          <span className="tcard__play">▶ Preview</span>
        </div>
      </div>

      {/* Body */}
      <div className="tcard__body">
        <div className="tcard__tags">
          {displayTags.map(tag => (
            <span key={tag} className={`tag tag-${color}`}>{tag}</span>
          ))}
          {level && <span className="tag tag-cyan">{level}</span>}
        </div>

        <h4 className="tcard__title">{title}</h4>
        {(provider || category) && (
          <p className="tcard__provider">{provider || category}</p>
        )}
        {description && (
          <p className="tcard__desc">
            {description.length > 80 ? description.slice(0, 80) + '…' : description}
          </p>
        )}

        <StarRating rating={rating} />
        <p className="tcard__reviews">({(reviews || 0).toLocaleString()} reviews)</p>

        <div className="tcard__metas">
          {duration && <span className="tcard__meta-item">📅 {duration}</span>}
          {level    && <span className="tcard__meta-item">📶 {level}</span>}
          <span className="tcard__meta-item">🏆 Certificate</span>
        </div>

        <div className="tcard__price-row">
          {price === 0
            ? <span className="tcard__price" style={{ color: 'var(--mint)' }}>🆓 Free</span>
            : <span className="tcard__price">₹{price.toLocaleString()}</span>
          }
        </div>

        <div className="tcard__footer">
          <span className="tcard__enrolled">
            👥 {enrolled >= 1000
              ? `${(enrolled / 1000).toFixed(1)}k`
              : enrolled} enrolled
          </span>
          <span className="tcard__enroll-btn">View →</span>
        </div>
      </div>
    </div>
  );
}
